+        let output =
+            b"\x1b[0m\x1b[?25h\x1b[?1049l\x1b[?1000;1002;1006l\x1b[?2004l\x1b[?1004l\x1b[<u";
+        assert_terminal_restored(output, &CleanupExpectations::strict());
